query:
-- Salse e Spezie: solo peso
UPDATE final_recipes SET measurementType = 'weight_only' WHERE code LIKE 'SALSA_%' OR code LIKE 'SPEZIE_%';

-- Tenders: sia peso che pezzi
UPDATE final_recipes SET measurementType = 'both', pieceWeight = 0.05097 WHERE code = 'CARNE_TENDERS';

-- Sovracosce: sia peso che pezzi
UPDATE final_recipes SET measurementType = 'both', pieceWeight = 0.06397 WHERE code = 'CARNE_SOVRACOSCE';

-- BBQ Ribs: solo peso
UPDATE final_recipes SET measurementType = 'weight_only' WHERE code = 'BBQ_RIBS';

-- Altre carni: solo peso
UPDATE final_recipes SET measurementType = 'weight_only' WHERE code LIKE 'CARNE_%' AND measurementType IS NULL;

-- Verdure: solo peso
UPDATE final_recipes SET measurementType = 'weight_only' WHERE code LIKE 'VERDURE_%';

